module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const tmin = Number.isFinite(parseFloat(args.tmin)) ? parseFloat(args.tmin) : 0;
const tmax = Number.isFinite(parseFloat(args.tmax)) ? parseFloat(args.tmax) : Math.PI * 2;
const palette = ['#2563eb', '#dc2626', '#16a34a', '#9333ea', '#ea580c'];
const funcs = [];
sections.map((s) => (s || '').trim()).filter(Boolean).forEach((s) => {
  const i = s.indexOf('|');
  const expr = (i >= 0 ? s.slice(0, i) : s).trim();
  const label = i >= 0 ? s.slice(i + 1).trim() : '';
  if (!/^[\w+\-*/().,^\s]*$/.test(expr)) return;
  let fn = null;
  try { fn = new Function('t', 'with(Math){return (' + expr.replace(/\^/g, '**') + ');}'); fn(0); } catch (e) { fn = null; }
  if (fn) funcs.push({ fn, label: label || expr });
});
if (!funcs.length) return `<div>(polarplot: one "expression | label" per section, e.g. 1 + cos(t))</div>`;
const sN = parseInt(args.samples, 10);
const N = Number.isFinite(sN) ? Math.max(30, Math.min(2000, sN)) : 360;
const fillOn = String(args.fill) === 'true';
const series = funcs.map((f) => {
  const pts = [];
  for (let i = 0; i <= N; i++) {
    const t = tmin + (tmax - tmin) * i / N;
    let r; try { r = f.fn(t); } catch (e) { r = NaN; }
    pts.push([t, typeof r === 'number' && Number.isFinite(r) ? r : NaN]);
  }
  return pts;
});
const rmax = Math.max(...series.flat().map((p) => Math.abs(p[1])).filter(Number.isFinite)) || 1;
const C = 70, R = 62;
const gx = (t, r) => C + (r / rmax) * R * Math.cos(t);
const gy = (t, r) => C - (r / rmax) * R * Math.sin(t);
let svg = '';
if (String(args.grid) !== 'false') {
  [0.25, 0.5, 0.75, 1].forEach((k) => { svg += `<circle cx="${C}" cy="${C}" r="${(R * k).toFixed(1)}" class="mdp-pp-ring"/>`; });
  for (let a = 0; a < 12; a++) {
    const th = (Math.PI * a) / 6;
    svg += `<line x1="${C}" y1="${C}" x2="${(C + R * Math.cos(th)).toFixed(1)}" y2="${(C - R * Math.sin(th)).toFixed(1)}" class="mdp-pp-spoke"/>`;
  }
  svg += `<text x="${C + R + 3}" y="${C}" class="mdp-pp-rlbl" dominant-baseline="middle">${(+rmax.toFixed(3))}</text>`;
}
series.forEach((pts, si) => {
  const c = palette[si % palette.length];
  let d = '', pen = false;
  pts.forEach((p) => {
    if (!Number.isFinite(p[1])) { pen = false; return; }
    d += (pen ? ' L' : ' M') + gx(p[0], p[1]).toFixed(1) + ',' + gy(p[0], p[1]).toFixed(1);
    pen = true;
  });
  if (d) svg += `<path d="${d.trim()}" class="mdp-pp-curve" style="stroke:${c};${fillOn ? ` fill:${c}; fill-opacity:0.12;` : ''}"/>`;
});
let legend = '';
const showLegend = String(args.legend) !== 'false';
if (showLegend && (funcs.length > 1 || funcs[0].label)) {
  legend = `<div class="mdp-pp-legend">` + funcs.map((f, i) =>
    `<span><i style="background:${palette[i % palette.length]};"></i>${esc(f.label)}</span>`).join('') + `</div>`;
}
const sw = parseFloat(args.thickness);
const swv = Number.isFinite(sw) ? Math.max(0.5, Math.min(5, sw)) : 1.2;
return `\n\n<div class="mdp-mod-polarplot" style="--pp-sw:${swv};"><svg viewBox="0 0 140 140" preserveAspectRatio="xMidYMid meet">${svg}</svg>${legend}</div>\n\n`;
